 }

@@ -1213,7 +1257,7 @@

 	new = palloc(option);
 	endch = 'c';
-	new->o_data = find_parsenum(new, option->name, size_str, &endch);
+	new->o_data = find_parsenum(new, option->name, size_str, "c", &endch);
